package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class LinkedTreeMap_ReplaceInParentTest {

  private LinkedTreeMap<String, String> map;

  private static class Node<K, V> {
    K key;
    V value;
    Node<K, V> parent;
    Node<K, V> left;
    Node<K, V> right;

    Node(K key, V value) {
      this.key = key;
      this.value = value;
    }
  }

  private Method replaceInParentMethod;
  private Field rootField;

  @BeforeEach
  void setUp() throws Exception {
    map = new LinkedTreeMap<>();

    // Access private replaceInParent method
    replaceInParentMethod = LinkedTreeMap.class.getDeclaredMethod("replaceInParent", Object.class, Object.class);
    replaceInParentMethod.setAccessible(true);

    // Access private root field
    rootField = LinkedTreeMap.class.getDeclaredField("root");
    rootField.setAccessible(true);
  }

  @SuppressWarnings("unchecked")
  private Node<String, String> createNode(String key, String value) {
    return new Node<>(key, value);
  }

  @Test
  void replaceInParent_replacesLeftChild() throws Exception {
    // Setup parent and node
    Node<String, String> parent = createNode("parent", "pVal");
    Node<String, String> node = createNode("node", "nVal");
    Node<String, String> replacement = createNode("replacement", "rVal");

    // Set parent-child relation: parent.left = node
    parent.left = node;
    node.parent = parent;

    // Call replaceInParent(node, replacement)
    replaceInParentMethod.invoke(map, node, replacement);

    // Verify node.parent is null
    assertNull(node.parent);

    // Verify replacement.parent == parent
    assertSame(parent, replacement.parent);

    // Verify parent's left is replacement
    assertSame(replacement, parent.left);

    // Verify parent's right unchanged (null)
    assertNull(parent.right);

    // Verify root unchanged (null)
    assertNull(rootField.get(map));
  }

  @Test
  void replaceInParent_replacesRightChild() throws Exception {
    // Setup parent and node
    Node<String, String> parent = createNode("parent", "pVal");
    Node<String, String> node = createNode("node", "nVal");
    Node<String, String> replacement = createNode("replacement", "rVal");

    // Set parent-child relation: parent.right = node
    parent.right = node;
    node.parent = parent;

    // Call replaceInParent(node, replacement)
    replaceInParentMethod.invoke(map, node, replacement);

    // Verify node.parent is null
    assertNull(node.parent);

    // Verify replacement.parent == parent
    assertSame(parent, replacement.parent);

    // Verify parent's right is replacement
    assertSame(replacement, parent.right);

    // Verify parent's left unchanged (null)
    assertNull(parent.left);

    // Verify root unchanged (null)
    assertNull(rootField.get(map));
  }

  @Test
  void replaceInParent_replacementIsNull() throws Exception {
    // Setup parent and node
    Node<String, String> parent = createNode("parent", "pVal");
    Node<String, String> node = createNode("node", "nVal");

    // Set parent-child relation: parent.left = node
    parent.left = node;
    node.parent = parent;

    // Call replaceInParent(node, null)
    replaceInParentMethod.invoke(map, node, null);

    // Verify node.parent is null
    assertNull(node.parent);

    // Verify parent's left is null (replacement null)
    assertNull(parent.left);

    // Verify parent's right unchanged (null)
    assertNull(parent.right);

    // Verify root unchanged (null)
    assertNull(rootField.get(map));
  }

  @Test
  void replaceInParent_nodeHasNoParent_rootUpdated() throws Exception {
    // Setup node with no parent
    Node<String, String> node = createNode("node", "nVal");
    Node<String, String> replacement = createNode("replacement", "rVal");

    // Set root to node
    rootField.set(map, node);

    // Call replaceInParent(node, replacement)
    replaceInParentMethod.invoke(map, node, replacement);

    // Verify node.parent is null
    assertNull(node.parent);

    // Verify replacement.parent is null (no parent)
    assertNull(replacement.parent);

    // Verify root is replacement
    assertSame(replacement, rootField.get(map));
  }

  @Test
  void replaceInParent_nodeHasNoParent_replacementNull_rootSetNull() throws Exception {
    // Setup node with no parent
    Node<String, String> node = createNode("node", "nVal");

    // Set root to node
    rootField.set(map, node);

    // Call replaceInParent(node, null)
    replaceInParentMethod.invoke(map, node, null);

    // Verify node.parent is null
    assertNull(node.parent);

    // Verify root is null
    assertNull(rootField.get(map));
  }
}
